const body = $json.body ?? $json;
const messageId = body.message_id ?? body.messageId ?? body.message?.id;

if (!messageId) {
  throw new Error('Classification request must include message_id.');
}

return [
  {
    json: {
      message_id: messageId,
      source: body.source ?? 'whatsapp_inbound',
      requested_at: new Date().toISOString()
    }
  }
];

const context = $json;
const message = context.message ?? {};
const contact = context.contact ?? {};
const conversation = context.conversation ?? {};
const recentMessages = context.recent_messages ?? [];

if (!message.id) {
  throw new Error('Supabase context lookup did not return a message.');
}

const schema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    intent: {
      type: 'string',
      enum: ['sales_lead', 'support_faq', 'reservation_booking', 'human_escalation', 'spam_noise', 'unknown']
    },
    confidence: {
      type: 'number',
      minimum: 0,
      maximum: 1
    },
    urgency: {
      type: 'string',
      enum: ['low', 'medium', 'high']
    },
    summary: {
      type: 'string'
    },
    recommended_action: {
      type: 'string'
    },
    missing_fields: {
      type: 'array',
      items: { type: 'string' }
    }
  },
  required: ['intent', 'confidence', 'urgency', 'summary', 'recommended_action', 'missing_fields']
};

const classifierInput = {
  business_context: {
    product: 'WhatsApp AI Triage Engine for LATAM service businesses',
    demo_business: 'EJDLV-style reservations and service inquiries',
    supported_intents: ['sales_lead', 'support_faq', 'reservation_booking', 'human_escalation', 'spam_noise', 'unknown']
  },
  contact,
  conversation,
  target_message: message,
  recent_messages: recentMessages
};

return [
  {
    json: {
      message_id: message.id,
      conversation_id: conversation.id,
      contact_id: contact.id,
      model: 'gpt-4.1-mini',
      prompt_version: 'intent-classifier-v1',
      input_context: context,
      openai_request: {
        model: 'gpt-4.1-mini',
        instructions: [
          'You classify inbound WhatsApp messages for a service-business triage system.',
          'Return only the structured JSON object requested by the schema.',
          'Use reservation_booking when the customer asks about dates, times, group size, availability, booking, or prices for a visit/reservation.',
          'Use sales_lead when the customer is interested in buying, pricing, quoting, or services but not specifically booking/reserving.',
          'Use support_faq for common operational questions that can be answered from known policy/context.',
          'Use human_escalation for complaints, unsafe situations, payment disputes, angry customers, legal/medical/emergency issues, or low confidence on a high-stakes reply.',
          'Use spam_noise for irrelevant, abusive, bot-like, or nonsensical messages.',
          'Use unknown when there is not enough information.',
          'Never invent prices, dates, policies, or availability. Recommended actions should ask for missing info or route to a human when needed.'
        ].join('\n'),
        input: JSON.stringify(classifierInput),
        text: {
          format: {
            type: 'json_schema',
            name: 'whatsapp_intent_classification',
            strict: true,
            schema
          }
        }
      }
    }
  }
];

const raw = $json;
const source = $('Build OpenAI Classification Request').item.json;

let text = raw.output_text;

if (!text && Array.isArray(raw.output)) {
  for (const outputItem of raw.output) {
    if (!Array.isArray(outputItem.content)) continue;
    const textPart = outputItem.content.find((part) => part.type === 'output_text' || part.text);
    if (textPart) {
      text = textPart.text;
      break;
    }
  }
}

if (!text) {
  throw new Error('OpenAI response did not include output_text.');
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (error) {
  throw new Error(`OpenAI classification JSON parse failed: ${error.message}`);
}

return [
  {
    json: {
      message_id: source.message_id,
      conversation_id: source.conversation_id,
      contact_id: source.contact_id,
      intent: parsed.intent,
      confidence: parsed.confidence,
      urgency: parsed.urgency,
      summary: parsed.summary,
      recommended_action: parsed.recommended_action,
      missing_fields: parsed.missing_fields ?? [],
      model: raw.model ?? source.model,
      prompt_version: source.prompt_version,
      input_context: source.input_context,
      raw_response: raw
    }
  }
];

const saved = $json;
const parsed = $('Parse OpenAI Classification').item.json;
const context = parsed.input_context ?? {};
const contact = context.contact ?? {};
const conversation = context.conversation ?? {};
const customerPhone = contact.phone_number;
const businessPhone = conversation.business_phone_number ?? 'whatsapp:+15550100000';
const intent = parsed.intent;
const missingFields = Array.isArray(parsed.missing_fields) ? parsed.missing_fields : [];

const missing = new Set(missingFields.map((field) => String(field).toLowerCase()));
let body = '';
let shouldSend = true;

if (intent === 'reservation_booking') {
  const asksGroupSize = missing.has('group_size') || missing.has('number_of_people') || missing.has('party_size');
  const asksPreferredTime = missing.has('preferred_time') || missing.has('time') || missing.has('schedule');

  if (asksGroupSize && asksPreferredTime) {
    body = 'Hola, con gusto te ayudo. Para cotizarte mejor, me puedes confirmar para cuantas personas seria y que horario prefieres?';
  } else if (asksGroupSize) {
    body = 'Hola, con gusto te ayudo. Para cotizarte mejor, me puedes confirmar para cuantas personas seria?';
  } else if (asksPreferredTime) {
    body = 'Hola, con gusto te ayudo. Me puedes confirmar que horario prefieres para revisar la disponibilidad?';
  } else {
    body = 'Hola, con gusto te ayudo. Ya tengo tu solicitud de reserva; te comparto la informacion y revisamos disponibilidad para la fecha que necesitas.';
  }
} else if (intent === 'sales_lead') {
  body = 'Hola, gracias por escribirnos. Con gusto te ayudo con la informacion. Me puedes contar un poco mas sobre lo que necesitas para orientarte mejor?';
} else if (intent === 'support_faq') {
  body = 'Hola, gracias por escribirnos. Con gusto reviso tu consulta y te comparto la informacion correspondiente.';
} else if (intent === 'human_escalation') {
  body = 'Gracias por avisarnos. Voy a pasar tu caso con una persona del equipo para que pueda ayudarte mejor.';
} else if (intent === 'unknown') {
  body = 'Hola, gracias por escribirnos. Me puedes dar un poco mas de detalle para ayudarte mejor?';
} else if (intent === 'spam_noise') {
  shouldSend = false;
}

if (!customerPhone) {
  shouldSend = false;
}

return [
  {
    json: {
      should_send: shouldSend,
      from: businessPhone,
      to: customerPhone,
      body,
      sender_type: 'ai',
      external_thread_id: conversation.external_thread_id,
      conversation_id: conversation.id,
      classification: saved,
      intent,
      confidence: parsed.confidence,
      urgency: parsed.urgency
    }
  }
];

const reply = $('Build Basic WhatsApp Reply').item.json;
let outbound = null;

try {
  outbound = $('Send Basic WhatsApp Reply').item.json;
} catch (error) {
  outbound = null;
}

return [
  {
    json: {
      ok: true,
      auto_reply_sent: Boolean(outbound),
      reply,
      outbound
    }
  }
];
